## 2. C/​C++ glue – `pcapng_stubs.cpp`

```cpp
/* ------------- pcapng_stubs.cpp -------------
   This file implements the three primitives declared in pcapng.mli.
   It must be compiled as C++ (e.g. with `ocamlc -ccopt -lstdc++` or a
   dune rule that uses `cxx`).

   The binding uses a small C++ wrapper around libpcapng's Reader
   class.  The Reader provides a forward‑only iterator over frames.
   For each frame we build an OCaml value of type `frame` (a 4‑tuple
   whose fields are a float, two ints and a `bytes` block) and then
   invoke the user‑supplied callback.
*/

#define CAML_NAME_SPACE
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/fail.h>

#include <string>
#include <cstring>   // memcpy
#include <exception>

#include "libpcapng/reader.hpp"   // <-- adjust to your actual header location

using namespace libpcapng;   // the namespace used by libpcapng

/* --------------------------------------------------------------
   1.  The opaque OCaml value that holds a pointer to the C++ Reader.
   -------------------------------------------------------------- */

typedef struct {
  Reader *reader;          // owned pointer, freed in the finaliser
} pcapng_handle;

/* Finaliser – called when the OCaml value is GC‑collected. */
static void pcapng_finalize(value v)
{
  pcapng_handle *h = (pcapng_handle *)Data_custom_val(v);
  if (h->reader) {
    delete h->reader;
    h->reader = nullptr;
  }
}

/* Custom operations descriptor – only a finaliser is needed. */
static struct custom_operations pcapng_ops = {
  "org.ocaml.libpcapng.pcapng",   /* identifier */
  pcapng_finalize,                /* finaliser */
  custom_compare_default,
  custom_hash_default,
  custom_serialize_default,
  custom_deserialize_default,
  custom_fixed_length_default
};

/* --------------------------------------------------------------
   2.  Helper: build an OCaml `frame` record from a libpcapng::Frame.
   -------------------------------------------------------------- */

static value caml_of_frame(const Frame &f)
{
  CAMLparam0();
  CAMLlocal4(ocaml_frame, ts_val, caplen_val, origlen_val, data_val);

  /* 1) timestamp (float) */
  ts_val = caml_copy_double(f.timestamp);

  /* 2) captured_len (int) */
  caplen_val = Val_int(static_cast<int>(f.captured_len));

  /* 3) original_len (int) */
  origlen_val = Val_int(static_cast<int>(f.original_len));

  /* 4) data (bytes) – copy the payload */
  data_val = caml_alloc_string(static_cast<size_t>(f.captured_len));
  if (f.captured_len > 0)
    std::memcpy(String_val(data_val), f.data, static_cast<size_t>(f.captured_len));

  /* Build a 4‑tuple {timestamp; captured_len; original_len; data} */
  ocaml_frame = caml_alloc(4, 0);
  Store_field(ocaml_frame, 0, ts_val);
  Store_field(ocaml_frame, 1, caplen_val);
  Store_field(ocaml_frame, 2, origlen_val);
  Store_field(ocaml_frame, 3, data_val);

  CAMLreturn(ocaml_frame);
}

/* --------------------------------------------------------------
   3.  Primitive: open_file : string -> t
   -------------------------------------------------------------- */
extern "C" CAMLprim value caml_pcapng_open_file(value v_path)
{
  CAMLparam1(v_path);
  CAMLlocal1(v_handle);

  const char *c_path = String_val(v_path);
  try {
    Reader *r = new Reader(std::string(c_path));
    /* Allocate a custom block to hold the pointer */
    v_handle = caml_alloc_custom(&pcapng_ops, sizeof(pcapng_handle), 0, 1);
    pcapng_handle *h = (pcapng_handle *)Data_custom_val(v_handle);
    h->reader = r;
    CAMLreturn(v_handle);
  } catch (const std::exception &e) {
    caml_failwith(e.what());
  } catch (...) {
    caml_failwith("pcapng: unknown error while opening file");
  }
}

/* --------------------------------------------------------------
   4.  Primitive: close : t -> unit
   -------------------------------------------------------------- */
extern "C" CAMLprim value caml_pcapng_close(value v_handle)
{
  CAMLparam1(v_handle);
  pcapng_handle *h = (pcapng_handle *)Data_custom_val(v_handle);
  if (h->reader) {
    delete h->reader;
    h->reader = nullptr;
  }
  CAMLreturn(Val_unit);
}

/* --------------------------------------------------------------
   5.  Primitive: iter_frames : t -> (frame -> unit) -> unit
   -------------------------------------------------------------- */
extern "C" CAMLprim value caml_pcapng_iter_frames(value v_handle,
                                                value v_callback)
{
  CAMLparam2(v_handle, v_callback);
  pcapng_handle *h = (pcapng_handle *)Data_custom_val(v_handle);
  if (!h->reader) caml_failwith("pcapng: handle is closed");

  try {
    /* Release the OCaml runtime while we walk the C++ iterator; we will
       reacquire it for every callback (so the callback can allocate, raise,
       etc.). */
    caml_release_runtime_system();

    for (Reader::iterator it = h->reader->begin(),
                         end = h->reader->end(); it != end; ++it) {
      const Frame &f = *it;

      /* Re‑acquire the runtime to build the OCaml value and invoke the
         callback. */
      caml_acquire_runtime_system();

      CAMLlocal1(ocaml_frame);
      ocaml_frame = caml_of_frame(f);   /* builds the tuple */

      /* Call the user supplied function.  If it raises, the exception
         propagates out of this C stub and iteration stops. */
      value res = caml_callback(v_callback, ocaml_frame);
      (void)res;   // we ignore the unit result

      caml_release_runtime_system();   // back to “C‑only” mode for the next frame
    }

    /* All frames processed – reacquire the runtime before returning. */
    caml_acquire_runtime_system();
    CAMLreturn(Val_unit);
  } catch (const std::exception &e) {
    caml_acquire_runtime_system();   // make sure we own the runtime before failing
    caml_failwith(e.what());
  } catch (...) {
    caml_acquire_runtime_system();
    caml_failwith("pcapng: unknown error during iteration");
  }
}

/* --------------------------------------------------------------
   End of pcapng_stubs.cpp
   -------------------------------------------------------------- */
```

